INSERT INTO `creature_text` (`CreatureID`, `GroupID`, `ID`, `Text`, `Type`, `Language`, `Probability`, `Emote`, `Duration`, `Sound`, `BroadcastTextId`, `TextRange`, `comment`) VALUES
(3500316, 0, 0, 'My beautiful fireworks! I''m going to tell on you!', 12, 0, 100.0, 18, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500315, 0, 0, 'Taking a kid''s fireworks? That''s pretty messed up. Mark my words, you''ll regret it!', 12, 0, 100.0, 18, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500314, 0, 0, 'Hey, those are mine! You won''t get away with this, $gmister:lady;!', 12, 0, 100.0, 18, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500309, 0, 0, 'Aww! Come on, you didn''t have to take them just yet. Let''s get outta here Shoob.', 12, 0, 100.0, 18, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 0, 0, 'I''ll get started on fixin'' it up with stuff I have around the shop.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500214, 0, 0, 'Ваш заказ в секретной комнате, $gгосподин:госпожа;.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500214, 1, 0, 'And we will answer from the shadows.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500088, 0, 0, 'Прекрасный выбор. А теперь я посвящу тебя в подробности нашего плана.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500099, 0, 0, 'Ну, если у вас нет времени, то и я не буду тратить на вас свое.', 12, 0, 100.0, 14, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500099, 1, 0, 'Тебе повезло, что Кадгар тебе доверяет. Имей в виду, я совершенно не разделяю его восторгов.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500099, 2, 0, 'You may enter the hold, but I will not put my guards'' lives at risk for your ''mission''. Is that clear?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500099, 3, 0, 'Lower the barrier and evacuate the hold. These Illidari wish to... exchange words... with the eredar.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500099, 4, 0, 'Follow me. I will open the cell for you.', 12, 0, 100.0, 25, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500099, 5, 0, 'Meet Taldath - one of the most powerful eredar we''ve ever encountered. I''m sure you two will be fast friends.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500099, 6, 0, 'Remember, demon hunter - you were never here.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500095, 0, 0, 'Нам нужно всего лишь недолго потолковать с эредаром... наедине. У него есть нужная нам информация.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500095, 1, 0, 'Crystal, Warden.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500439, 0, 0, 'Иллидари! Этот бес стащил гримуар! Поймай его!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500151, 0, 0, 'Мой лучший гиппогриф идеально подойдет для этой задачи.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500236, 0, 0, 'Идем, $gгерой:воительница;. Я покажу тебе истинную силу Крутогорья.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500052, 0, 0, 'We''re in luck, warbrave. The champion you seek should be here shortly.', 12, 0, 100.0, 273, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500052, 1, 0, '$p, the warbrave has good intentions - I think. Quickly, now, after him - his people are your best chance at an ally on that mountain.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500308, 0, 0, 'Да, вполне. Большое тебе спасибо!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500443, 5, 0, 'Смотри, чтобы оно не досталось врагу.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500443, 4, 0, 'Надо сказать, это мое лучшее творение.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500443, 3, 0, 'Твое оружие будет острым и прочным. Оно пробьет любой доспех и никогда не подведет тебя в бою.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500443, 1, 0, 'Наверное, непросто было достать такую древесину и руду.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500295, 3, 0, 'Отлично! У меня есть для тебя новый рецепт, $p.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500295, 4, 0, 'Bring me more ingredients, Master $p. Meat, fish, blood... whatever you can find out there in the scary outdoors. I will help you turn them into delicious dishes!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500295, 2, 0, 'С пивком, наверное, вышло бы еще лучше...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500295, 0, 0, 'Так, для начала попробуем продольное филетирование...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500295, 1, 0, 'А вот это интересно! Если удалять кости уже после завяливания, мяса в отходы уходит меньше...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500113, 0, 0, 'Пора в путь. Флот Темной Госпожи уже почти готов выдвинуться.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500263, 1, 0, 'Вечные страдания. Никакой пощады Карии.', 12, 0, 100.0, 66, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500263, 0, 0, 'Аллари вела отряд на поиски потерянных боевых клинков. Возможно, мы наконец нашли их.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500265, 0, 0, 'Алтруис, есть идеи.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 6, 0, 'Возьмешь? Эти кристаллы имеют свойство отторгаться от существ недемонической природы.', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500097, 0, 0, 'Of course, I apologize, but actually this is my stone. Maybe you won’t touch him?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500031, 0, 0, 'Щелкните по находящейся поблизости точке прикрепления крюка, чтобы запрыгнуть на стену. Точки прикрепления крюка в радиусе досягаемости подсвечиваются.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 0, 0, 'They say I died in the Deadmines. Fools - it''s all too simple to mimic the effects of death when your assailants'' minds are addled by neurotoxins.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 1, 0, 'Did you know that I was favored to become the final Shadow and that despite their assurances every single one of them put in their lot with you instead?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 2, 0, 'It''s a pity, really - Jorach did so much for me. He won''t be happy when he comes to and you''re dead.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 3, 0, 'Let''s see how long you last.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 4, 0, 'Ничего личного. Просто бизнес.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 5, 0, 'Come on, show me the ''legendary fighter'' I''ve heard so much about!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 6, 0, 'No! I''ve worked too hard to be undermined by the likes of you!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 7, 0, 'Stop. Stop! No more!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 8, 0, 'Пожалуй, я воспользуюсь вашим щедрым предложением.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500251, 0, 0, 'Valeera nods.', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500087, 0, 0, 'Vanessa...?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500087, 1, 0, 'Oh, my head... Valeera, you ok?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 0, 0, 'Hear, hear. I''d like to propose a toast.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 1, 0, 'Today, $p secured the legendary Dreadblades, and in doing so has enabled us to strike at the Legion directly.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 2, 0, 'Join me in raising a glass not only to our newest Shadow, but to the dawn of a new era for the Uncrowned.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 3, 0, 'VanCleef, the Uncrowned still have use of you. You have a choice - live and work as one of $p''s agents... or die where you stand.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 4, 0, 'Then it''s settled. Congratulations, $p. VanCleef is one of our best - as you''ve seen firsthand.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 5, 0, 'Your father would have been disappointed in you, Vanessa', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500079, 0, 0, 'ОЙ! Вот это великан!', 14, 0, 100.0, 22, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 11, 0, 'ЧТО ЭТО ЗА ТВАРЬ?!', 14, 0, 100.0, 22, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500281, 0, 0, 'ОЙ! Так ГОРАЗДО лучше.', 12, 0, 100.0, 53, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500281, 1, 0, 'Значит, это Даларан? Джабрул поражен. К ювелирам – сюда?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 10, 0, '$n,  I thought I asked you to tell your friend to STOP sending those letters of his?!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 9, 0, ' I myself would never dream of going down there, but I assume you''d have no problem given your primary career |3-1($c)', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 8, 0, 'I don''t currently have any, no. But I hear they have all sorts of items in the Underbelly.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500215, 1, 0, 'Да, конечно. Вон они, на столе. А что, с ними что-то не так?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 6, 0, 'Думаю, начать стоит с Катрионы Макрей. Она была моей последней клиенткой.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500574, 0, 0, 'I''ll meet you down in Azsuna, <name>. Come find me when you discover something.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500097, 5, 0, 'Мой камень? Да, без проблем. Он лежит на приставном столике.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500068, 0, 0, 'Glaciela, I swear, your teeth are going to fall out one day from eating all my delicious candies.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500059, 0, 0, 'You need my help in the blacksmithing shop? Fine, but every mage has her price... and my price happens to be candy.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500062, 1, 0, 'All done! You take care of that mount now. It''s a beauty.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500062, 0, 0, 'You need your mount shod? Let''s see if I can make these hoofplates fit...', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500573, 1, 0, 'This core contains a script written in an ancient Highborne dialect, which I can''t read. Professor Pallin in the Scribes'' Sacellum may be able to translate this.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500573, 0, 0, 'The Data Extratinator 3000 might be able to decipher this core. Cross your fingers that it doesn''t explode in the process.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 3, 0, 'Look how easily it bends...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 4, 0, 'And now for the simple step of applying the flux. Lean in closely and watch my technique.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 15, 0, 'Эй! Не эту! А ну отдай!', 12, 0, 100.0, 61, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 14, 0, 'Вытяните карту. Любую карту.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 13, 0, 'Так, для следующего фокуса мне понадобится помощник. Кто хочет быть добровольцем?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 12, 0, 'И... оп-па!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 11, 0, 'Спасибо, большое спасибо. Я очень благодарен вам за ваши пожертвования.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 10, 0, 'Дамы и господа, не откажите себе в удовольствии увидеть настоящие чудеса ловкости рук!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 8, 0, 'Pick a card, any card...', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 9, 0, 'Hey! Not that card! Give it back!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 6, 0, 'And... bam!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 7, 0, 'Okay, for this trick I''ll need a volunteer.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 5, 0, 'And now for my next trick! As you can see, there''s nothing up my sleeve...', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 4, 0, 'Ladies and gentlemen, feast your eyes on these feats of prestidigitation!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 2, 0, 'Thank you, thank you. Your tips are appreciated.', 12, 0, 100.0, 2, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 3, 0, 'Gather ''round and witness mystical wonders like you''ve never seen before!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 1, 0, 'Gaze in astonishment as I produce a rabbit from this ordinary hat!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 0, 0, 'Step right up! Behold the amazing magical talents of the Great Akazamzarak!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500396, 0, 0, 'Ey mon, dat there be da one Garona spoke of.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500088, 1, 0, 'Something''s off about this here brew...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500044, 0, 0, '$n, сюда.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500354, 0, 0, 'We are everywhere. We are Legion.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500251, 2, 0, 'Akaari... your time has come.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500251, 3, 0, 'Akaari retreated upstairs as we arrived. She''s all yours.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500251, 4, 0, 'Val''zuun, I will be your death!', 14, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500355, 0, 0, 'I should thank you. You''ve saved me the effort of finding you.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413');
INSERT INTO `creature_text` (`CreatureID`, `GroupID`, `ID`, `Text`, `Type`, `Language`, `Probability`, `Emote`, `Duration`, `Sound`, `BroadcastTextId`, `TextRange`, `comment`) VALUES
(3500355, 1, 0, 'Kil''jaeden will be pleased when I bring him your head.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500355, 2, 0, 'One by one, you will all fall to the Fangs.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500355, 3, 0, 'Kirel volosh!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500355, 4, 0, 'Miserable worm. Die!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500355, 5, 0, 'You think my master so foolish...?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500124, 0, 0, 'Nothing to share, I''m afraid. The wine gets people talking, but sometimes they just don''t have anything useful to say.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500124, 1, 0, 'Say, care for some Moist Azsunian Feta while you''re here? It has a lovely tangy flavor!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500303, 0, 0, 'Ты $gвернулся:вернулась; с артефактом! Молодец, $n!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500226, 3, 0, 'Tell me if you need my help, |3-6($c).', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500226, 0, 0, 'Well Met!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500226, 0, 1, 'Well Met.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500101, 0, 0, 'Приветствую вас! Пожалуйста, осмотрите мои товары.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500101, 0, 1, 'Приветствую.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 4, 0, 'Порошок чар... осколки душ... нет, не то...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 5, 0, 'Ага! Вот он! Кристалл души. Вот это пойдет.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500060, 0, 0, 'I''d be happy to! Have a look at my stock, $n.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500210, 3, 0, 'Yablochkin notices the Incinerator and throws you an apple!', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 6, 0, 'Тогда по рукам. Поздравляю тебя, $p. Ван Клиф у нас одна из лучших – как тебе уже пришлось убедиться.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500293, 7, 0, 'Твой отец был бы очень разочарован тобой, Ванесса.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 0, 0, 'Времени в обрез. Этот портал перенесет нас прямо в Аметистовую крепость.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500048, 0, 0, 'If he wished to use the blade for his own ends, he would have simply given it to one of his Sunreavers.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500048, 1, 0, 'Aethas''s actions appear to be genuine. I say we grant his request.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 3, 0, 'Наверное, туда засунул.', 12, 0, 100.0, 25, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 2, 0, 'Так-так, посмотрим... апекситовые кристаллы? Нет, они совсем не подойдут.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500347, 0, 0, 'Открываю портал!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500047, 0, 0, 'How do we know he won''t betray the Kirin Tor once again?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500047, 1, 0, 'Very well, I trust the wisdom of Karlain''s council. I vote yes.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500046, 0, 0, 'Khadgar, what''s wrong? What happened?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 1, 0, 'Когда раздобудешь артефакт, $n, возвращайся сюда. Я за это время постараюсь привести тут все в порядок.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 2, 0, 'Ну что, Аказамзарак, все координаты у тебя. Сможешь провесить порталы?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 3, 0, 'Маги Азерота! Я собрал вас здесь пред лицом угрозы всему нашему миру!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 4, 0, 'Повелитель ужаса Катра''натир сбежал в Круговерть Пустоты, унеся с собой секреты Совета Тирисфаля.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 5, 0, 'Мы должны отправиться за ним в Круговерть Пустоты и отыскать его там. Лишь тогда мы будем уверены, что он не сможет использовать свои знания против нас.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 6, 0, 'С этой целью я восстанавливаю орден Стражей Тирисфаля. И я призываю вас присоединиться к нам и поднять оружие против Легиона! Вы с нами?!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 7, 0, 'Значит, решено.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 8, 0, 'Отлично. В присутствии величайших магов Азерота нарекаю тебя $n, $gКолдун:Колдунья; Стражей Тирисфаля.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 9, 0, 'Этот древний титул в свое время носили старейшие из магов Азерота, и он символизирует огромную ответственность, возложенную на Стражей Тирисфаля. Носи же его с гордостью и честью.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 10, 0, 'А теперь ступай в Зал Войны и познакомься с нашим новым союзником из гоблинов. Можете сразу начинать планировать ваши дальнейшие шаги.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 11, 0, 'Мне нужно отлучиться по личному делу...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500422, 0, 0, 'Calydus know where that is! Calydus can help!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500046, 1, 0, 'Something bit your head? That''s all? Would you like me to kiss it for you?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500060, 1, 0, 'Yes, yes... We all know how attached you are to your alchemy table!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500061, 0, 0, 'Приветствую тебя, |3-6($c).', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500443, 2, 0, 'С этим материалом трудно работать, но поверь, результат тебе понравится.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500443, 0, 0, 'Халдарон сказал, что ты придешь.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500059, 1, 0, 'Consider me hired. See you there!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500446, 0, 0, 'If there is any chance of aid, then we will come. Stay, Dawnbreaker.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500447, 0, 0, 'Tyrosus is a good man - count me in. It''s too dangerous these days to not seek a bit of help.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500447, 1, 0, 'We may not be alone in this after all, Tahu! Let''s see what Tyrosus has to say.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500360, 0, 0, 'I have some ability to speak with the long departed. We may be able to question the hero in this saga directly.', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500359, 1, 0, 'I found a vrykul saga describing a powerful shield Tyr crafted for his vrykul champion to carry into battle.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500359, 2, 0, 'Aye, that''s my hope. With your help, we have a chance of finding this artifact.', 12, 0, 100.0, 5, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500359, 3, 0, 'The tower in the middle o'' Dalaran has a portal to Wyrmrest Temple. Should get ye most o'' the way there. Tahu, thanks again fer helping us paladins.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500359, 0, 0, 'Since the defeat of the Lich King, I''ve spent my time around Ulduar learning about Tyr. He was the only titan keeper who fought Loken during his betrayal.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500360, 1, 0, 'You asked the Sunwalkers for aid, and I have come. May my presence bring success to your quest, Orik.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500418, 0, 0, 'My brother spoke of a dragon called Lanigosa at Wymrest Temple. Start with her. I will prepare a strike force for the tomb.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500418, 1, 0, 'I will prepare our forces for the journey to Tirisfal. You can make your way there through the portal to Dalaran Crater.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500418, 2, 0, 'Найди наших уцелевших братьев и собери их у гробницы.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500105, 0, 0, 'Нагорье повержено. Силы клана рассеяны.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500105, 1, 0, 'Они нас выследили!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500105, 2, 0, 'The Doomhammer fell somewhere below. Hold on! This part always gives me tummy the wubblies!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 4, 0, 'Выходит, повелители ужаса научились создавать нежить, неотличимую от живых! Даже я не распознаю ее с первого взгляда!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 0, 0, 'Of course, I am an experienced undead hunter, but I did not immediately notice something was wrong.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 11, 0, 'Будь осторожнее. Сурамар десять тысяч лет пребывал в запустении.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 10, 0, 'Если эту штуку потревожить, процесс пойдет. Э-э... ткни ее, что ли.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 9, 0, 'Не трогайте! Дождитесь нашего гостя.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500207, 1, 0, 'Ты что, думаешь, тебе кто-нибудь что-нибудь даст за здорово живешь? Извиняй, дорогуша, но услуга за услугу.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500207, 1, 1, 'Я могу сменять тебе лом на несколько новых манекенов для доспехов. У Иминдрил Песни Копья в лавке "Танки – наше все" как раз должна найтись парочка.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500263, 2, 0, 'Встретимся у крепости.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500207, 1, 2, 'Принеси их мне, и лом твой.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500057, 1, 0, 'Да, у меня есть несколько манекенов про запас, но я пока не готова с ними расстаться. Разве что...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500057, 1, 1, 'Не хочешь быстренько сбегать по одному небольшому поручению? Если все сделаешь, манекены твои.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500057, 2, 0, 'Ну, Шанди молодец... знает, как вывести с одежи кровищу! Вот, держи свои манекены – все как было обещано.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500207, 4, 0, 'А ты не $gторопился!:торопилась!; Что, небось, на обратном пути остановилась пропустить кружечку? Ладно, вот тебе лом, как мы и договаривались.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500585, 0, 0, 'Hello, $n! I want to warn you I can repair not all bugged and not working achievements, quests etc.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 10, 0, 'Убийство в союзном городе – слишком рискованное дело, но если ты прирежешь гомункула в Луносвете, вопросов не возникнет. А мы займемся целями в Экзодаре.', 12, 0, 100.0, 274, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 9, 0, 'Помни... хоть ты и пытаешься помочь, Орда все равно сочтет это нападением на одного из своих.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 8, 0, 'Помни... хоть ты и пытаешься помочь, Альянс все равно сочтет это нападением на одного из своих.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 7, 0, 'Убийство в союзном городе – слишком рискованное дело, но если ты прирежешь гомункула в Экзодаре, вопросов не возникнет. А мы займемся целями в Луносвете.', 12, 0, 100.0, 274, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 6, 0, 'Наши агенты вычислили этих тварей в Экзодаре и Луносвете.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 5, 0, 'Демоны поняли, что им не укрыться от иллидари в наших городах, и на сей раз отправили этих... гомункулов.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500215, 0, 0, 'Well Met.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500539, 2, 0, 'Конечно, темница Катра''натира не сможет долго подпитывать оборону Даларана. Но я безмерно рад, что сущность демона останется под замком. Пора возвращаться в Оплот Хранителя.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500078, 3, 0, 'Well Met!', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500084, 0, 0, 'Did Eitrigg send you? I must thank him for his concern, but it is unnecessary.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500084, 1, 0, 'Death is the likely end there, you know this. I can see in your eyes that I cannot talk you out of this, perhaps you have honor to regain there as well.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 0, 0, 'У меня есть как раз то, что нужно. Иди за мной.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500301, 0, 0, 'Итак, на том и порешили. Кстати, поговори с Веленом. У него к тебе... весьма необычное дело.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500357, 1, 0, 'Он внутри. Прошу тебя, сделай все возможное, чтобы его спасти.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500357, 2, 0, 'Баррем!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500357, 4, 0, 'Встретимся на площадке Краса и полетим на остров на моем грифоне.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 12, 0, 'So Arrexis was ambushed by this eredar, Balaadur?  He is probably in possession of the staff now then...', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500318, 13, 0, 'Let us recreate Arrexis''s ritual! If we start the ritual at an invasion point, that will attract Balaadur''s attention. He will likely ambush us, but we will be ready.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 1, 0, 'Let me just insert this into the core and we''ll see what happens.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 5, 0, 'I suppose I can part with one. But tell Didi I''m sending her a bill for it. We''re not running a charity here.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500307, 0, 0, 'Who throws a bandage at someone? Honestly?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500307, 0, 1, 'What the...?! I guess that feels better.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500307, 0, 2, 'Ugh! Oh, my head...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 8, 0, 'Success!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500477, 0, 0, 'Welcome to Dalaran! I''m happy to assist with anything you need.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413');
INSERT INTO `creature_text` (`CreatureID`, `GroupID`, `ID`, `Text`, `Type`, `Language`, `Probability`, `Emote`, `Duration`, `Sound`, `BroadcastTextId`, `TextRange`, `comment`) VALUES
(3500043, 0, 0, 'А вот и ты, $n. Идем, Азсуна ждет.', 12, 0, 100.0, 396, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500043, 1, 0, 'Дай мне знать, когда можно отправляться, $n.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500070, 0, 0, 'Well Met!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500029, 0, 0, 'Взрывчатка заложена! Отойдите на безопасное расстояние и подорвите ее!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500029, 1, 0, 'In-Game Cutscene', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 8, 0, 'Something... bit my head I thing.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 7, 0, 'OW!! What in the light was that?!', 14, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500357, 0, 0, 'Это $gжрец:жрица;, хвала Свету!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 5, 0, 'Are you alright? *Cough, cough* I''m thinking the only thing that''s going to work here is a fel-infused core.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 4, 0, 'Alright, I''m going to pour in the solution now. Watch yourself, not sure how this is going to react.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 3, 0, 'Go to the alchemy shop and ask Deucus for a potion with some punch in it.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 2, 0, 'Flashy, but ineffective. We''ll have to try something else. Maybe we need a chemical reaction.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500307, 0, 3, 'What just hit me!?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500307, 0, 4, 'Thanks for the heal!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500307, 0, 5, 'I don''t know what you just did... but I LIKE it!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 7, 0, 'You found something?! That''s amazing! You''re amazing, $n! Keep your fingers crossed, I''m gonna put it in now.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500571, 6, 0, 'It''s a long shot, but there may be someone here in Dalaran who has one. Try asking Bonegrim in the Ledgerdemain Lounge if he''s come across any.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 0, 0, 'Следуй за мной, $n. "Небесный огонь" готов к отправлению.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 1, 0, 'В Штормхейме покоится Эгида Агграмара, один из Столпов Созидания.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 2, 0, 'По легенде, ее может получить лишь тот, кто сумеет пройти особое испытание.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 3, 0, 'Впечатляет, правда? Из новых орудий можно сбить виверну с трехсот метров на полном ходу. Взгляни-ка.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 4, 0, 'Нам приказано доставить тебя в Штормхейм и помочь в прохождении испытания.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 5, 0, 'Кроме того, нам поручена и другая задача...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 6, 0, 'Седьмой легион. Самые суровые ребята в Альянсе. Они тоже выполняют личный приказ короля.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 7, 0, 'Три дня назад флот Отрекшихся вышел из Дуротара к Расколотым островам. Мы считаем, что его возглавляет сама Сильвана.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 8, 0, 'Мы должны проследить за этим флотом, но при этом постараться избежать прямых стычек.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 9, 0, 'Хотя, по-моему, они неизбежны.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500112, 10, 0, 'Приготовления почти завершены. Устраивайтесь поудобнее.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 0, 0, 'Приветствую.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500477, 2, 0, 'I must inform the Council of your news. Good luck, $n!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 1, 0, 'Now let''s see what we can make with it.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 2, 0, 'Shaping the ore...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 0, 0, 'Alright, let''s see what we can do with this ore. First things first: we heat the ore.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500253, 0, 0, 'Ith''el kanesh!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500253, 1, 0, 'I am Thalyssra of the shal''dorei - the Nightborne. First Arcanist in the court of Suramar.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500253, 2, 0, 'My people have made a dire pact. One that spells doom for this world.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500253, 3, 0, 'Time is short. If you have found this message, you are capable of finding me as well.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500253, 4, 0, 'Make haste for Suramar. You may be our last hope.', 12, 0, 100.0, 25, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500253, 5, 0, 'Ith''nala kanesh!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500175, 0, 0, 'Is $n seeing anyone? Do you think I''d have a chance?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500454, 0, 0, 'Вижу, охота прошла успешно! Да я и не сомневался.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500057, 1, 2, 'I want to give my dress to Shandi. It was all smeared with soot.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500248, 0, 0, 'Be careful, boss. Outland''s a pretty dangerous place, an'' Shattrath''s not that much better.', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500248, 1, 0, 'Watch your back, and your pockets.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500248, 2, 0, 'Just make sure to tell everyone to be real nice to him. Otherwise, we might all wake up dead tomorrow. Ya know what I mean?', 12, 0, 100.0, 5, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500389, 0, 0, 'Прекрасный выбор. Я позабочусь о том, чтобы все было сделано как следует. Всегда приятно работать с профи высшего класса вроде тебя, $n.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500144, 0, 0, 'Классно выглядишь, $n!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500144, 1, 0, 'Тьфу на тебя, $n! Снова щеголяешь в своих крутых очках?! Прекрасно!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500144, 2, 0, 'А вот и $n... ты глянь, какие очки!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500144, 3, 0, 'Не знаете, $n встречается с кем-нибудь? У меня есть шансы?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 3, 0, 'Говорил он складно, и кожа... выглядела вполне нормально. Но все-таки я его вычислила.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 2, 0, 'Ты не пожалеешь об этом. Я убью любого демона или прислужника Легиона, что встанет у меня на пути!', 12, 0, 100.0, 66, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 10, 0, 'Грейсон будет доволен нашей работой. Передай ему мои наилучшие пожелания.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 9, 0, 'Готово! Одна из лучших моих работ, как по мне! Можешь забирать.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 8, 0, 'И наконец – главная драгоценность!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 7, 0, 'А теперь хорошенько отковать заготовку из силового камня... вот здесь... и-и-и здесь...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 6, 0, 'Сперва надо переплавить всю руду...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500572, 5, 0, 'Ну, давай-ка посмотрим, что можно сделать с этим доспехом.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500127, 2, 0, 'But if you think you can finish what Antonidas started, then the piece is yours. Good luck with it, Archmage $n.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500127, 1, 0, 'After Antonidas died, I decided to hide the disc away. There was no reason to continue my research into it.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500127, 0, 0, 'I haven''t thought of that since... well since an old friend asked about it shortly before he was taken from this world.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 13, 0, 'I was working with Archmage Alturus on it at the time. He may still know where it resides. You''ll find him just outside of Karazhan.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 12, 0, 'You''re speaking of the Tri-Disc of Fire. Yes, he gave it to me, but that was a long time ago. Back when I was still studying at Karazhan.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500539, 0, 0, 'I will open the portal to the enchantress Rihanna. One moment...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500539, 1, 0, 'I will call the portal. See you on the other side, Archmage $n!', 12, 0, 100.0, 25, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500086, 3, 0, 'I swear, I''m staying put. No more exploring the city for me. I''m happy right here in the tailoring shop.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500071, 1, 0, 'I just got a fresh shipment of Runic Catgut, $n. If your supply is low, you can buy some from me.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500086, 2, 0, 'Please, use my table in the middle of the room to perform your tasks. You''ll find some Runic Catgut on it as well.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500086, 1, 0, 'Э-э...Я просто...присматривал новые красители для ткани. Да-да. Новые красители. Я немедленно вернусь в ателье.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 3, 0, 'Проще простого...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 4, 0, 'Готово! И передай Танитрии, что за ней теперь еще одна шелковая подушка.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500195, 3, 0, 'Давай, Акван. Твой выход.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500195, 4, 0, 'Вот твое платье. Смотри – ни пятнышка; прямо как новое! Спасибо тебе за помощь.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500195, 2, 0, 'Славно. Сейчас я с него мигом всю грязь отстираю!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500195, 1, 0, 'Да, конечно, я могу постирать это платье. Только я беру 2 золотых за работу.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500045, 1, 0, 'Подожди секундочку. Я, знаешь ли, такой барахольщик...', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500071, 4, 0, 'Hold on a sec... there! I''ve got him!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500071, 3, 0, 'A summon? Sure! Where did you say he was?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500071, 2, 0, 'Oh. $n. I have some Spritethorns for sale if you need any for your bag recipe.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500357, 3, 0, 'I''ll go with you. You helped one of mine, so I will repay you with a service for the service.', 12, 0, 100.0, 25, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500075, 0, 0, 'Well Met.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500097, 2, 0, 'А, хорошо. Сейчас спущусь. Уже иду!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500097, 3, 0, 'Эй! Кто там меня разыскивал?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500097, 4, 0, 'Интересно, куда они все подевались... Ну ладно. Может, еще вернутся.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500247, 0, 0, 'Да, у меня есть то, что тебе нужно. Но просто так я это отдавать не собираюсь. Вот поменяться – это другое дело.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500247, 1, 0, 'Тут наверху лежит один красивый красный камушек, который мне сразу пришелся по душе. Раздобудь его для меня, и я тебе сменяю на него твой сердечник.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500247, 2, 0, 'Приятно иметь с тобой дело, $gприятель:подруга;.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500486, 0, 0, 'Этот портал ведет в Экзодар. Удачи тебе, $ct.', 12, 0, 100.0, 397, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500512, 0, 0, 'Эй! Я видел, что уволок демон. Иди сюда, я все расскажу.', 12, 0, 100.0, 22, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500532, 1, 0, 'Сердце Круула... плохо дело.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500491, 0, 0, 'Тсс! Говори тише...', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500491, 0, 1, 'Говори тише! Здесь кто-то есть...', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500169, 0, 0, 'А вот и $n... ты глянь, какие очки!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500076, 0, 0, 'Он на полке спрятался. Ну не прелесть?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500430, 3, 0, 'Tell me if you need my help, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500531, 0, 0, 'Что она натворила?! Портал перегрузился и соединился с Пустотой!', 12, 0, 100.0, 5, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500531, 2, 0, 'Ладно, попробую стабилизировать портал. Надеюсь, ты знаешь, что делаешь, |3-6($c)!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500531, 3, 0, 'Стой... что-то не так! Не могу... сдержать...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500531, 4, 0, 'Ох!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500531, 12, 0, 'Кажется, руны сработали! Энергия Скверны угасает...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413');
INSERT INTO `creature_text` (`CreatureID`, `GroupID`, `ID`, `Text`, `Type`, `Language`, `Probability`, `Emote`, `Duration`, `Sound`, `BroadcastTextId`, `TextRange`, `comment`) VALUES
(3500531, 13, 0, 'Готово.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500532, 0, 0, 'Банк? Как они...', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500532, 2, 0, 'Никогда не поручай магам работу охотников на демонов!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500533, 0, 0, 'Похоже, судьбе было угодно вновь свести нас вместе, |3-6($c).', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500154, 0, 0, 'Боюсь, мы об этом узнаем еще не скоро. Внутренние помещения все еще объяты пламенем Скверны!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500153, 0, 0, 'Мы даже не знаем, миновала ли опасность, а ты спрашиваешь про хранилище?! Туда допускаются только члены Совета Шестерых!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500512, 1, 0, 'Он так трясся за эту вещицу, что слинял сразу же, как только вышел из хранилища', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500031, 0, 1, 'Click on a nearby hook attachment point to jump on a wall. The hook attachment points within range are illuminated.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500152, 0, 0, 'Ну и какая разница? В хранилище собраны наши самые ценные реликвии! Пропажа любой из них – катастрофа!', 12, 0, 100.0, 5, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 16, 0, 'Вы остолбенеете, когда я на ваших глазах вытащу кролика из самой обычной шляпы!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500324, 0, 0, 'Wow! A golden Dr. Boom!', 12, 0, 100.0, 5, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500250, 1, 0, 'А что, если ударить его вот сюда...', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500485, 3, 0, 'I really want to become like you.', 12, 0, 100.0, 2, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500532, 3, 0, 'Демоны могли спрятаться в банке. Будь начеку.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500533, 1, 0, 'Итак... Круул возвращается.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500531, 14, 0, 'Фамбар взял след. Ступай за ним в портал, и он приведет тебя к пропавшей чародейке.', 12, 0, 100.0, 25, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500048, 2, 0, 'Отправляйся на Расколотый берег, там тебя ждет Карам! Он прямо сейчас разведывает местность вокруг гробницы.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500096, 0, 0, 'Вот так, парень! Если увидишь мамочку, скажешь ей, что у меня почти не осталось отмычек?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500585, 1, 0, 'SAY TEST', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500295, 30, 0, 'Ваш заказ будет готов через 5 минут.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500087, 2, 0, 'Ты не пожалеешь об этом. Я убью любого демона или прислужника Легиона, что встанет у меня на пути!', 12, 0, 100.0, 66, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500341, 0, 0, 'Портал почти готов!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500341, 1, 0, 'Вуаля!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500339, 0, 0, 'Отлично, $n! Ты справляешься на ура и, похоже, $gспособен:способна; на большее... Обращайся, если интересно!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500568, 0, 0, 'WARN: SPEAR_OF_DOOM', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500568, 1, 0, 'WARN: WARN_FINAL_DOOM', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500568, 2, 0, 'WARN: PURGE', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500568, 3, 0, 'WARN: RAIN_OF_FEL', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500528, 3, 0, 'Используйте |TInterface\\Icons\\SPELL_SHADOW_ENSLAVEDEMON.BLP:20|t |cFFFF0000|Hspell:111771|h[Порабощение демона]|h|r, чтобы подчинить скакуна гнева!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500531, 1, 0, 'I will try to stabilize it! Hold back the demons!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500499, 3, 0, 'Я должна ее купить! Детали просто изумительно выписаны!', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500499, 3, 1, 'Это без преувеличения изысканное творение.', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500495, 3, 0, '%s фыркает.', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500495, 0, 0, '%s оглушительно храпит.', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500490, 3, 0, 'Здесь такой крепкий кофе!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500490, 3, 1, 'Ну и когда эта Фе''бе соизволит явиться? Она вроде обещала быть здесь еще час назад!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500487, 3, 0, 'Успокойтесь. Наверняка она появится с минуты на минуту.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500485, 3, 1, 'Мы все будем брать с тебя пример.', 12, 0, 100.0, 2, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500485, 3, 2, 'Возможно, мы все еще сможем спастись!', 12, 0, 100.0, 2, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500485, 3, 3, 'Заклинаю тебя, будь аккуратнее с этим посохом...', 12, 0, 100.0, 2, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500483, 3, 0, 'Отлично выглядишь, $n! Просто отлично!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500485, 3, 4, 'Fury of the Light ... she was considered to be missing ...', 12, 0, 100.0, 2, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500477, 3, 0, 'А теперь мне нужно заняться другими гостями. Удачи тебе, $n!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500477, 3, 1, 'Ресурсы Даларана в твоем распоряжении. С этого дня главная задача всех героев Альянса и Орды – поиск Столпов Созидания!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500475, 3, 0, 'Встретимся в Покое. Удачного тебе пути.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500512, 2, 0, 'I only remember that in form this thing resembles a heart. Doesn’t say anything?', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500466, 3, 0, 'Теперь у нас есть Слезы Элуны. Пусть они принесут нам победу над Пылающим Легионом!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500466, 0, 0, 'Сегодня мы празднуем великую победу, оплаченную кровью друзей и близких.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500466, 3, 1, 'Благодаря твоей смелости древние земли Валь''шары смогут исцелиться.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500453, 3, 0, 'Я на это не подписывался.', 15, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500453, 3, 1, 'Рыбалка? ...Кроме шуток?!', 15, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500424, 3, 0, 'I, like all my people, are indebted to you.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500445, 3, 0, 'Тьфу на тебя, $n! Снова щеголяешь в своих крутых очках?!', 12, 0, 100.0, 1, 0, 4415, 0, 0, 'Legion Dalaran 1413'),
(3500438, 3, 0, 'Это твое оружие – оно проклято, $n. Сколько моряков оно погубило на моем веку, кто бы знал. Осторожнее с ним.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500437, 0, 0, 'Впервые увидев тебя, я молила духов о том, чтобы тебе можно было доверять. И вот благодаря тебе наши племена вновь едины.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500437, 3, 0, 'Именем племен Крутогорья вверяю этот молот тебе и твоим союзникам. Пусть он сокрушит любого врага!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500431, 3, 0, 'До скорой встречи.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500431, 0, 0, 'Весьма неплохой дом для смертного. Ну-ка, посмотрим, что он тут прячет.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500429, 3, 0, 'Да будет так. Обрати эту великую силу против врагов Тирисфаля!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500426, 3, 0, 'Лучше, если все это останется между нами, |3-6($c). Не зря говорят: болтун – находка для шпиона.', 12, 0, 100.0, 273, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500424, 3, 1, 'Столько веков прошло с тех пор, как я видел Приливный камень целым – и вот он, передо мной.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500402, 3, 0, 'Отлично выглядишь, $n! Просто отлично!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500395, 3, 0, 'Тьфу на тебя, $n! Снова щеголяешь в своих крутых очках?!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500381, 3, 0, 'Уделишь мне минутку, $n? У меня есть кое-что интересное.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500376, 3, 0, 'Сейчас все прошло как по маслу, но в будущем на это потребуется больше времени.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500317, 3, 0, 'У твоего оружия открылось очень интересное прошлое. Это добавлено в книгу – взгляни, если желаешь.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500317, 0, 0, 'Ну вот, $n. Мы провели в изысканиях недели и, думаю, раскопали об истории твоего оружия все, что только можно.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500317, 3, 1, 'Последняя глава нашей книги завершена. Тебе определенно стоит прочесть.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500317, 3, 2, 'У твоего оружия, как оказалось, довольно-таки богатое прошлое. В книгу добавлены новые переводы, можешь взглянуть.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500317, 0, 1, 'Это исследование весьма занимательно! Я как раз вписываю переведенную историю в книгу.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500317, 3, 3, 'В книгу добавлены новые факты по истории твоего оружия. Тебе стоит взглянуть, когда будет время.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500317, 0, 2, 'Спасибо за такой внушительный вклад в наше исследование. Надеюсь, что результаты наших изысканий оказались полезными.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500226, 3, 1, 'Приветствую тебя, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500226, 0, 2, 'Приветствую вас! Пожалуйста, осмотрите мои товары.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500217, 3, 0, 'Не знаете, $n встречается с кем-нибудь? У меня есть шансы?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500210, 3, 1, 'Yablochkin notices G''khanir and throws you a fresh apple!', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500126, 3, 0, 'Осторожнее, $n, не споткнись! Есть новости от Совета?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500126, 3, 1, 'Что там происходит? Шумят все громче и громче. Надеюсь, что скоро мы узнаем хоть что-нибудь.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500126, 3, 2, 'Как там дела, $n? Посетители приходят и уходят, но никто толком ничего не знает.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500120, 3, 0, 'Приветствую вас! Пожалуйста, осмотрите мои товары.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500120, 3, 1, 'Приветствую тебя, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500120, 3, 2, 'Well Met!', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500120, 0, 0, 'Tell me if you need my help, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500207, 0, 0, 'Well Met!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500080, 3, 0, 'Приветствую тебя, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500080, 3, 1, 'Приветствую.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500078, 3, 1, 'Приветствую тебя, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500080, 3, 2, 'Tell me if you need my help, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500078, 3, 2, 'Приветствую вас! Пожалуйста, осмотрите мои товары.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500080, 3, 3, 'Welcome. May I help you in your search?', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 0, 1, 'Well Met!', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500078, 3, 3, 'Tell me if you need my help, |3-6($c).', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500078, 3, 4, 'Well Met.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500080, 3, 4, 'Well Met.', 12, 0, 100.0, 3, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500033, 0, 0, '$n $gпоймал:поймала; громадного грозного краба!', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500033, 3, 0, 'Спальник Ку-Яо пустой. Его здесь нет.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500033, 3, 1, 'На щите выгравировано "Часовой Ку-Яо". Щит принадлежит отцу мальчишки.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500033, 0, 1, '$n $gпоймал:поймала; красарангского предка!', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500033, 0, 2, '$n $gпоймал:поймала; древного багряноголового журавля!', 16, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500053, 3, 0, 'Шаман! У меня срочное сообщение.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413');
INSERT INTO `creature_text` (`CreatureID`, `GroupID`, `ID`, `Text`, `Type`, `Language`, `Probability`, `Emote`, `Duration`, `Sound`, `BroadcastTextId`, `TextRange`, `comment`) VALUES
(3500053, 3, 1, '$n! У меня срочное сообщение.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500069, 3, 0, 'Надеюсь, запасы редкой руды в нашем хранилище порадуют тебя больше.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500093, 3, 0, 'That there be $p. I heard $Ghe:she; took down Deathwing with nothin'' but the blades in $Ghis:her; hands!', 12, 0, 100.0, 396, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500093, 3, 1, 'Ищешь что-нибудь конкретное?', 12, 0, 100.0, 5, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500093, 3, 2, 'Вот это $p. Говорят, $gон завалил:она завалила; Смертокрыла одними своими клинками!', 12, 0, 100.0, 396, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 12, 1, 'И... Whoa, whoa, whoa!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500102, 3, 0, 'О, какая прелесть! Коробка новых игрушек!', 12, 0, 100.0, 4, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500125, 3, 0, 'А вот и $n... ты глянь, какие очки!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500146, 3, 0, '$n! Is it true you wield the Kingslayers? When I was just a girl, my gran told me the stories. The King of Stormwind grasping at his throat, red blood spattered on the white stones of the keep... I would hide under my covers at night, thinking assassins were everywhere.', 12, 0, 100.0, 5, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500220, 3, 0, 'Отлично выглядишь, $n! Просто отлично!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500262, 3, 0, 'Встретимся у крепости.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500262, 3, 1, '$p, Отчаяние Тьмы и Гребень Ворона проводят тебя в Сурамар. У маленького отряда больше шансов незаметно проникнуть в крепость.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500262, 3, 2, 'Darksorrow and Ravencrest will have the honor to accompany $p into Suramar. A small force will have the best chance of flying undetected into the hold.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500262, 3, 3, 'Darksorrow, Ravencrest, you will have the honor to accompany $p into Suramar. A small force will have the best chance of flying undetected into the stronghold.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500287, 3, 0, 'На протяжении очень долгих лет дренеи скрывались от Пылающего Легиона. Все это время наару очень помогали нам; иногда даже ценой своей жизни. Без их помощи нам бы точно пришел конец.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500287, 3, 1, 'Маги организовали для нас портал. Идем. Я хочу рассказать тебе кое-что о наару и дренеях.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500306, 3, 0, 'Увы, Орест погиб. Нужно отправить весть Халдарону. Идем, Быстрошпор.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500319, 3, 0, 'Тебе понравится, $p. Догоняй!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500319, 3, 1, 'Ты идешь, $p?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500319, 3, 2, 'Coming, $p?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 0, 'Пожалуйста, сохраняйте спокойствие и соблюдайте очередность. Банкир обслужит вас, как только сможет.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 1, 'Спокойно! Всем сохранять спокойствие! Этот врайкул надолго здесь не задержится!', 14, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 2, 'Совет просит сохранять спокойствие, пока они оценивают ситуацию.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 3, 'Easy! Easy there! I hope that vrykul leaves soon!', 14, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 4, 'Кто-то проник в хранилище!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 5, 'Просим вас проявить терпение – скоро мы сообщим вам все подробности.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 6, 'Мы должны сохранять спокойствие, пока Совет не завершит расследование.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500340, 3, 7, 'Мы с Советом активно работаем над урегулированием ситуации.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500345, 3, 0, 'Можем долететь на этих гиппогрифов до Штормхейма и там ждать сигнала Вухо!', 12, 0, 100.0, 396, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500348, 3, 0, 'Грег, я плачу тебе, чтоб ты танцевал, а не кис тут! Так что давай, подвигай попой!', 12, 0, 100.0, 22, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500363, 3, 0, 'Полетели, $n. Легкокрыл оседлан и готов.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500363, 3, 1, 'Полетели, $n. Легкокрыл оседлан и готов отправляться в путь.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500364, 3, 0, 'Запрыгивай на птичку и следуй за мной! В Штормхейм!', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500461, 3, 0, 'Иллидари! Врата открыты. Все на "Молот Скверны"!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500461, 0, 0, 'Ваши души – мои!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500481, 3, 0, 'Кушайте хорошо, если хотите вырасти большими и сильными и докачаться до двадцать пятого уровня.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500509, 1, 0, '"Я зна-аю, что ты работаешь на Легио-он". Вот что ты думаешь. Вот, на что похоже твое бормотание.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500521, 3, 0, 'Жаль, что Штормхейма не видно.', 12, 0, 100.0, 6, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500533, 2, 0, 'Обращай взор к Свету. Я исцелю твои раны.', 14, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500079, 0, 1, 'OOPS! What a giant!', 14, 0, 100.0, 22, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 11, 1, 'WHAT THE HELL IS THAT THING?!', 14, 0, 100.0, 22, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500072, 6, 1, 'I think we should start with Catriona McRae. She was my last client.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500215, 1, 1, 'Yes, of course. There they are, on the table. Why, is there something wrong with them?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500097, 5, 1, 'My stone? Yeah, no problem. It''s on the side table.', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 14, 1, 'Pull out the map. Any card.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 13, 1, 'Okay, for the next trick, I''m gonna need an assistant. Who wants to volunteer?', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 10, 1, 'Ladies and gentlemen, don''t deny yourself the pleasure of seeing the real wonders of hand dexterity!', 12, 0, 100.0, 1, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 15, 1, 'Hey! Not that one! Give it back!', 12, 0, 100.0, 61, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 4, 1, 'Its nothing personal. Its just business.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500304, 8, 1, 'I think Ill take your generous offer.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500281, 0, 1, 'OOPS! It''s better this way.', 12, 0, 100.0, 53, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500281, 1, 1, 'So that''s Dalaran? Jabrul is impressed. To the jewelers, here?', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413'),
(3500320, 11, 1, 'Thank you, thank you so much. I''m very grateful to you for your donations.', 12, 0, 100.0, 0, 0, 0, 0, 0, 'Legion Dalaran 1413');
